var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"하, 하늘에서 새하얀 마물들이 내려오고 있어……!","JPN":"そ、空から白い魔物たちが降りて来ている……！","ENG":"Th-there are white monsters coming down from the sky...!","TWN":"哈、哈！天上有雪白的怪物降臨了……！"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"아니야, 저건 마물이 아니야……!","JPN":"違う、あれは魔物じゃない……！","ENG":"No, those aren't monsters...!","TWN":"不是的，那不是怪物……！"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"저건 틀림없이 우리를 구원해주기 위해 하늘에서 내려온 천사라고……!","JPN":"あれはきっと私たちを救うために空から降りてきた天使なんだ……！","ENG":"Those are angels that have come down from heaven to save us...!","TWN":"那一定是為了拯救我們從天而降的天使……！"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"오오! 천사님, 부디 우리의 죄를……!","JPN":"おお！　天使よ、どうか我々の罪を……！","ENG":"Oh, angels! Please forgive our sin–","TWN":"喔喔！天使大人，請寬恕我們的罪過……！"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"젠장, 이건 말도 안 되잖아!","JPN":"くそっ、こんなのあり得ない！","ENG":"Damn it, this is insane!","TWN":"該死，這算什麼？！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"한 눈에 봐도 이 세계에 넘어온 6종 침식체가 다섯은 넘어……!","JPN":"ざっと見ただけでも、この世界に渡ってきた第6種侵食体が5体はいる……！","ENG":"Even at a glance, there are more than five Category 6 C.O.s that crossed over...!","TWN":"一眼就能看出，這個世界出現的6類侵蝕體已經超過五種！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그 뿐만이 아니야… 그 여파로 하위 침식체들까지 무더기로 출몰하고 있어……!","JPN":"それだけじゃない……その影響で下位侵食体までわんさか出てきて……！","ENG":"And it's not just them... low-level C.O.s are also pouring in...!","TWN":"不僅如此……由於這個影響，低級侵蝕體也成群出現了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이대로 가다간 정말로……!","JPN":"このままだと、マジで……！","ENG":"If this keeps up, we're really gonna die...!","TWN":"這樣下去真的！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"실망이네요, 카나리아 스쿼드.","JPN":"がっかりです、カナリア・スクワッド。","ENG":"How disappointing, Canary Squad.","TWN":"真讓人失望啊，金絲雀小隊。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 목격했던 이 세계의 멸망은 아직 시작하지도 않았습니다.","JPN":"私が目撃したこの世界の滅亡は、まだ始まってすらいませんよ。","ENG":"The end of this world I foresaw hasn't even begun.","TWN":"我所目睹的這個世界的毀滅還沒有開始。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세계를 바꿀 수 있는 변수를 자처하더니, 겨우 이정도로 절망하는 건가요?","JPN":"世界を変える変数を自負しておいて、この程度で絶望するのですか？","ENG":"You claimed to be the variables that would change the world, but you're already this hopeless?","TWN":"自稱是能改變世界的變數，結果就因為這種程度的事情而絕望嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"노엘…! 제 목소리가 들려요……?","JPN":"ノエル……！　聞こえますか……？","ENG":"Noelle...! Can you hear me...?","TWN":"洛艾兒！你能聽到我的聲音嗎……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"정신 차려요…! 당장 제가 그리로 갈 테니까……!","JPN":"しっかりしてください……！　私がすぐに行きます……！","ENG":"Snap out of it...! I'll come get you right now...!","TWN":"振作一點！我馬上就過去……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"진정해, 꼬맹이!","JPN":"落ち着け、おこちゃま！","ENG":"Calm down, kid!","TWN":"冷靜點，小鬼！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"지금, 이 대열에서 네가 빠지면 우리 전부 죽는다고……!","JPN":"今、この隊列からあんたが抜けたら、こっちは全員死ぬんだ……！","ENG":"If you leave the formation now, we're all dead...!","TWN":"現在，如果你從這個隊伍中退出，我們全都會死！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"이거 놔요, 라이카……!","JPN":"離して、ライカ……！","ENG":"Let go of me, Laika...!","TWN":"放開這個，萊卡！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그새 잊어버렸어요? 우리가 여기까지 온 건, 저 아이를 구하기 위해서였잖아요!","JPN":"忘れたの？　私たちがここに来たのは、あの子を助けるためよ！","ENG":"Did you already forget why we came all this way? We're here to save her!","TWN":"這麼快就忘了嗎？我們來到這裡是為了救那個孩子啊！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그 노엘이 저기 있어요! 조금만 달려가면 손 닿을 거리에 있는데……!","JPN":"そのノエルがあそこにいるのよ！　ちょっと走ると、手の届く距離に……！","ENG":"That's Noelle over there! She's just a hand reach away...!","TWN":"那邊就是洛艾兒！她就在伸手可及的距離……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"나도 알고 있어! 그래서 어쩔 건데?","JPN":"私だって知ってるよ！　でもどうするんだ？","ENG":"I know! But so what?!","TWN":"我也知道！那又怎樣？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"여기서 잠시나마 하늘에 떠 있는 허신을 땅으로 떨어트릴 수 있는 건, 너뿐이잖아!","JPN":"この中で一瞬でも空に浮いている虚神を落とせるのは、あんただけなのに！","ENG":"You're the only one who can bring down the Hollow God floating up there, even for a moment!","TWN":"在這裡能暫時將天空中的虛神拉到地面的，只有你啊！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그럼, 라이카는 노엘을 저대로 내버려두자는 거예요?","JPN":"じゃあ、ライカはノエルをあのままにしていいの？","ENG":"So you're saying we just leave Noelle behind?!","TWN":"那麼，萊卡是說要把洛艾兒就那樣放著不管嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"젠장, 그럴 리가 있겠냐……!","JPN":"くそ、そんなわけあるか……！","ENG":"Damn it, of course not...!","TWN":"可惡，怎麼可能！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"어이, 유미나! 무슨 방법이 없는 거야?","JPN":"おい、ミナ！　なんか方法はないのか！","ENG":"Hey, Yoo Mina! You got anything?","TWN":"喂，劉米娜！？有辦法了嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이대로 가면, 계속해서 허신 숫자만 불릴 뿐이라고……!","JPN":"このままじゃ、虚神が増え続けるだけだ……！","ENG":"At this rate, we're just gonna end up with even more of those Hollow Gods...!","TWN":"這樣下去，只會不斷增加虛神的數量！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"제길, 나도 알아……!","JPN":"くっ、わかってる……！","ENG":"Damn it, I know...!","TWN":"該死，我也知道！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇지만 방법이…….","JPN":"でも方法が……","ENG":"But I don't see a way...","TWN":"但是沒有辦法……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아니, 방법이라면 있어.","JPN":"いや、方法ならある。","ENG":"Actually, there is a way.","TWN":"不，我有辦法。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"방법이라고……?","JPN":"うん？　どういうこと……？","ENG":"There is...?","TWN":"辦法？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"에이미, 너 설마……?","JPN":"エイミー、あなたまさか……？","ENG":"Amy, you're not thinking...","TWN":"艾米，你該不會？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"무슨 짓이야, 유미나! 저리 비켜……!","JPN":"何すんの、ミナ！　さっさとどけって……！","ENG":"What are you doing, Yoo Mina?! Get out of the way...!","TWN":"你在幹什麼？劉米娜！讓開……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"웃기지 마, 에이미! 네가 지금 무슨 짓을 하려는 지 알기나 해?","JPN":"ふざけないで、エイミー！　あなた、今自分が何をしようとしているのか、わかってるの？","ENG":"Don't be ridiculous, Amy! Do you even realize what you're about to do?!","TWN":"別開玩笑了，艾米！你知道你現在想做什麼？？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그러는 너는? 지금 저 꼬맹이가 네 후배라서 감싸고 있는 것뿐이잖아……!","JPN":"そういうあんたは？　あのガキがあんたの後輩だから庇ってるだけじゃん……！","ENG":"And what about you? You're only protecting that kid because she's your junior...!","TWN":"那你呢？現在只是因為那個小鬼是你的後輩，所以才護著她吧！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐라고……?","JPN":"な、なんだって……？","ENG":"W-what...?","TWN":"什，什麼？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"비켜! 네가 못하면 내가 해줄 테니까!","JPN":"退きな！　あんたに出来ないなら、あたしがやってやる！","ENG":"Move! If you can't do it, I will!","TWN":"閃開！如果你做不到，我來幫你！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"냉정하게 생각해, 유미나.","JPN":"冷静になりなよ、ミナ。","ENG":"Think clearly, Yoo Mina.","TWN":"冷靜思考，劉米娜。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L13_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이 세계가 저 새하얀 허신으로 뒤덮이기 전에, 결정해야 한다고……!","JPN":"この世界があの真っ白な虚神だらけになる前に、決めなきゃいけないんだ……！","ENG":"Before those white Hollow Gods cover the world, we have to make a decision...!","TWN":"在這個世界被那純白的虛神覆蓋之前，必須做出決定！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"당신……!","JPN":"あなた……！","ENG":"Hey...!","TWN":"你……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"지금 이게 무슨 짓이에요! 하마터면 노엘이 맞을 뻔했잖아요……!","JPN":"どういうつもりですか！　下手したらノエルに当たるところでした！","ENG":"What are you doing?! You almost hit Noelle...!","TWN":"你現在在做什麼？差點就射中洛艾兒了……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"틀렸어, 꼬맹아.","JPN":"違うね。","ENG":"You're wrong, kid.","TWN":"錯了，小鬼。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"맞을 뻔한 게 아니라, 맞추려고 한 거야.","JPN":"当たりそうになったんじゃなくて、当てようとしたの。","ENG":"I didn't almost hit her, I was trying to.","TWN":"不是差點被打中，而是故意瞄準的。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"네에……?","JPN":"はい……？","ENG":"What...?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"쳇, 역시 이 거리에서는 무리인가?","JPN":"ちっ、やっぱこの距離じゃ無理か？","ENG":"Tch, I guess it's not possible at this range.","TWN":"嘖，果然在這個距離上還是不行嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 이제야 눈치챈 건가요, 리트리버.","JPN":"ふふ、やっと気づきましたか？　レトリーバー。","ENG":"Haha, you just now figured it out, retriever?","TWN":"呵呵，現在才發現嗎？獵犬。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"상황 판단이 빠른 당신 치고는 깨닫는 게 늦은 편이네요.","JPN":"状況判断の早いあなたにしては、ずいぶんと遅かったですね。","ENG":"You're usually quick to assess a situation. Took you long enough.","TWN":"以你判斷情況的速度，這次的領悟有點慢呢。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L27_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"시끄러워! 나는 이 미적지근한 녀석들이랑은 다르다고!","JPN":"うるさい！　あたしはこの生温い連中とは違う！","ENG":"Shut up! I'm nothing like these lukewarm jokers!","TWN":"閉嘴！我和這些不溫不火的傢伙不一樣！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"세피라 얘기가 나올 때부터 대충 눈치채고 있었어.","JPN":"セフィラの話になった時から、薄々感づいてはいた。","ENG":"I started suspecting as soon as you brought up Sephira.","TWN":"從提到生命樹的時候，我就大概猜到了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"네 옆에 있는 그 꼬맹이를 족치면 모든 게 해결된다는 걸 말이야……!","JPN":"あんたの隣にいるそのガキをぶっ飛ばせば、全部解決するってね……！","ENG":"Everything gets fixed if we take out that brat standing next to you...!","TWN":"只要收拾掉你旁邊那個小鬼，一切就能解決了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐, 뭐라고요……?","JPN":"な、何ですって……？","ENG":"W-what...?","TWN":"什，什麼？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"당신 제정신이에요? 지금 무슨 소리를 하는 거야?","JPN":"正気ですか？　何を言っているの？","ENG":"Are you insane?! What are you even saying?!","TWN":"你瘋了嗎？你現在在說什麼？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이봐, 형씨! 다시 말해봐! 지금 누가 누굴 족친다고……?","JPN":"おい、あんた！　もう一遍言ってみろ！　誰が誰をぶっ飛ばすって……？","ENG":"Hey, pal! Say that again! Who do you think you're taking out...?","TWN":"喂，兄弟！你說一遍！？現在是誰要幹掉誰？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"쫑알쫑알…! 둘 다 시끄럽다고! 이 짹짹이들아……!","JPN":"ピーチクパーチクと……！　うるさいな、この鳥ども……！","ENG":"Blah blah blah...! Shut up, both of you! You noisy little birds...!","TWN":"嘰嘰喳喳的……！你們兩個都很吵！這些小麻雀……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"조금만 생각해 보면, 당연한 거잖아……!","JPN":"ちょっと考えてみればわかることじゃん……！","ENG":"Come on, just think for a second, it's obvious...!","TWN":"稍微想一想，這不是理所當然的嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"결국 이 세계를 되돌린 건, 스완의 <color=#ffd34c>기억</color>과 저 꼬맹이가 가진 <color=#ffd34c>세피라</color>의 힘이야.","JPN":"結局この世界を元に戻したのは、スワンの<color=#ffd34c>記憶</color>とあのガキの持つ<color=#ffd34c>セフィラ</color>の力なんだよ。","ENG":"The reason this world came back is because of Swan's <color=#ffd34c>memory</color> and <color=#ffd34c>Sephira's</color> power that brat has.","TWN":"最終讓這個世界恢復原狀的，是史旺的<color=#ffd34c>記憶</color>和那個小鬼擁有的<color=#ffd34c>生命樹</color>的力量。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L43_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그럼, 둘 중 하나만 없어져도, 이 세계가 멸망하는 순간을 재현할 수 없는 거잖아?","JPN":"じゃあ、どっちかだけでも消えれば、この世界が滅亡する瞬間を再現できなくなるってことじゃない？","ENG":"So if just one of those is gone, there's no way to recreate the world's destruction again, right?","TWN":"那麼，只要其中一個消失，就無法重現這個世界滅亡的瞬間了吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이 세계 자체가 없었던 게 되어버리면, 저 허신들도 전부 사라져 버린다고……!","JPN":"この世界自体がなかったことになれば、あの虚神たちも全て消え去る……！","ENG":"If this world never existed in the first place, those Hollow Gods would disappear too...!","TWN":"如果這個世界本身消失了，那些虛神也會全部消失！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"기억…? 세피라…? 허신들이 사라져……?","JPN":"記憶……？　セフィラ……？　虚神たちが消える……？","ENG":"Memory...? Sephira...? The Hollow Gods would disappear...?","TWN":"記憶……生命樹……虛神們消失了？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그게 다 무슨 헛소리야? 이야기를 못 따라가겠다고!","JPN":"何言ってるんだ？　話についていけない！","ENG":"What kind of nonsense is that?! I can't follow any of this!","TWN":"這都是什麼意思？我跟不上你們的對話！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아이씨! 개인 과외 해줄 시간 없어!","JPN":"ああ、もう！　個人レッスンしてる暇なんてないんだ！","ENG":"Damn it! I don't have time to tutor you!","TWN":"哎呀！？沒時間給你做私人輔導！？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"지금 당장 움직여야 해!","JPN":"今すぐに動かないと！","ENG":"We need to move right now!","TWN":"現在要馬上行動！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"웃기지 마세요……!","JPN":"ふざけないで……！","ENG":"Don't be ridiculous...!","TWN":"別說笑了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"우리는 노엘을 구하러 여기까지 온 거예요!","JPN":"私たちはノエルを助けるためにここまで来たんです！","ENG":"We came all this way to save Noelle!","TWN":"我們是來這裡救洛艾兒的！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"우리가 어떻게 여기까지 왔는데, 그런 걸 허락할 것 같아요?","JPN":"どんな思いでここまで来たと思ってるんですか？　そんなの、許すわけありません。","ENG":"After everything we've been through, you think we're just gonna let that happen?","TWN":"我們好不容易來到這裡，你覺得會我們會允許你做那種事情嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"허락? 너나 웃기지 마, 꼬맹아!","JPN":"許すだ？　あんたこそ、ふざけないでよね。","ENG":"Let that happen? Don't make me laugh, kid!","TWN":"允許？別鬧了，小鬼！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"내가 왜 일일이 네 허락을 받아야 하지?","JPN":"あたしが何でいちいちあんたの許可を取らなきゃいけないわけ？","ENG":"Why would I need your permission for anything?","TWN":"我為什麼事事都得到你的允許？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"나는 이 상황을 해결할 수 있는 가장 효율적인 결론을 내놓은 것뿐이야.","JPN":"あたしは、今この状況を解決できる一番効率的な結論を出したまで。","ENG":"I'm just laying out the most efficient way to end this mess.","TWN":"我只是提出了一個能解決這個情況的最有效的結論而已。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"굳이 스완을 상대하는 것보다, 저 얼빠진 꼬맹이를 노리는 편이 더 성공 확률이 높으니까!","JPN":"律儀にスワンの相手するよりも、あの間抜けなガキを狙った方が成功する確率が高いから！","ENG":"It's way easier to take down that dazed brat than to go head-to-head with Swan!","TWN":"與其對付史旺，不如瞄準那個傻乎乎的小鬼，成功的幾率更高！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"당장 급한 불은 꺼야 할 거 아니야! 스완은 그 뒤에 쓰러트리면 돼……!","JPN":"目の前の火を消すのが先だろ！　スワンを倒すのはそれからでも遅くない……！","ENG":"We need to put out the biggest fire first! We can deal with Swan afterward...!","TWN":"現在必須先滅掉緊急的火！史旺可以之後再解決……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그럼, 노엘은요? 노엘한테는 아무 잘못도 없잖아요!","JPN":"じゃあ、ノエルは？　ノエルには何の罪もないじゃないですか！","ENG":"What about Noelle? She hasn't done anything wrong!","TWN":"那麼，洛艾兒呢？洛艾兒沒有任何過錯啊！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그런데 스완을 쓰러트리기 위해서, 지금 노엘을 희생시키자고요?","JPN":"それなのにスワンを倒すために、ノエルを犠牲にすると言うんですか？","ENG":"And you're saying we should sacrifice her just to take Swan down?!","TWN":"但是為了打倒史旺，現在就要犧牲洛艾兒嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그래…! 그렇지 않으면 더 많은 희생을 치러야 할지도 모르니까……!","JPN":"そうだよ……！　じゃなきゃ、もっとたくさんの犠牲が出るかもしれないから……！","ENG":"Yes...! Because otherwise, we might end up losing a lot more people...!","TWN":"對！不然的話可能要付出更多的犧牲……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그게 너나 나나 저 메이드가 될 수도 있으니까……!","JPN":"それがあんたやあたし、あのメイドになるかもしれないから……！","ENG":"And that could be you, or me, or even that maid over there...!","TWN":"因為你我都有可能成為那個女僕！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아니면, 꼬맹이 네가 이 상황을 감당할 수 있겠어?","JPN":"それとも何？　あんたがこの状況を何とかできるっていうの？","ENG":"Or are you saying you can take responsibility for this whole situation, kid?","TWN":"不然的話，小鬼你能應付這種情況嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Kgh...!","TWN":"呃！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"아무튼 저는 반대라고요……!","JPN":"とにかく私は反対です……！","ENG":"Either way, I still say no...!","TWN":"總之我反對！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"역병의 악취를 맡은 거짓된 신들이 하나둘씩 그 모습을 드러내고 있다.","JPN":"疫病の悪臭を嗅ぎつけた偽りの神たちが、次々とその姿を現している。","ENG":"The stench of plague has drawn the Hollow Gods, one by one.","TWN":"聞到瘟疫惡臭的虛神們一個個現出了真身。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_START_BIG"},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 세계의 종말이 멀지 않았으니, 필히 결정해야 한다. 다른 세계의 이방인들이여.","JPN":"この世界の終末が目前に迫っている。決断の時だ、異世界の異邦人たちよ。","ENG":"The end of this world is near. You must decide, outsiders from another world.","TWN":"這個世界的終結已經不遠，必須做出決定。異界的陌生人們。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……둘 다 그만둬.","JPN":"……二人ともそこまで。","ENG":"...That's enough, both of you.","TWN":"……你們兩個都停下。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"미나 씨?","JPN":"ミナさん？","ENG":"Mina?","TWN":"米娜？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"유미나, 뭘 어쩌려고?","JPN":"ミナ、どうするつもり？","ENG":"Yoo Mina, what else can we do?","TWN":"劉米娜，你想幹什麼？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"허신이 모여들기 시작한 이상, 우리한테 선택지 같은 건 없어.","JPN":"虚神が集まってきている今、あたしたちに選択肢なんてない。","ENG":"Now that the Hollow Gods have started gathering, we don't have any other options.","TWN":"既然虛神開始聚集，我們就沒有選擇的餘地了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알고 있어.","JPN":"わかってる。","ENG":"I know.","TWN":"我知道。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"だけど……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 이제 더 이상 그 누구도 잃고 싶지 않아.","JPN":"だけど、もうこれ以上誰も失いたくないの。","ENG":"But I don't want to lose anyone else.","TWN":"但是現在我不想再失去任何人了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"에이미도… 펠리세트와 라이카도… 그리고 노엘도……. 나에게는 전부 소중한 사람들이니까.","JPN":"エイミーも……フェリセットやライカも……そしてノエルも……私にはみんな大切なんだ。","ENG":"Amy... Félicette, Laika... and Noelle too... You're all important to me.","TWN":"艾米……費莉塞特和萊卡……還有洛艾兒……對我來說都是重要的人。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 스완을 쓰러트리자.","JPN":"だからスワンを倒そう。","ENG":"Let's take down Swan.","TWN":"所以我們打倒史旺吧。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"바로 여기서.","JPN":"今ここで。","ENG":"Right here, right now.","TWN":"就在這裡。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"미나 씨…….","JPN":"ミナさん……","ENG":"Mina...","TWN":"米娜……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"알겠어요, 한 번 해보죠.","JPN":"わかりました、やってみましょう。","ENG":"Okay. Let's do it.","TWN":"好的，就試試看吧。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"좋아, 까짓 거 죽기밖에 더 하겠어?","JPN":"いいよ、最悪死ぬだけだろうし。","ENG":"All right. Worst case, we die, right?","TWN":"好吧，那就拼個你死我活。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"한 번 시작했으면, 끝까지 가야지. 안 그래, 형씨?","JPN":"始めたからには、最後までやり通さなきゃな。そうだろう？","ENG":"If we've come this far, we're going all the way. Isn't that right?","TWN":"一旦開始了，就要堅持到底。不是嗎？兄弟？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"제정신이야, 유미나?","JPN":"本気で言ってんの？　ミナ。","ENG":"Are you serious, Yoo Mina?","TWN":"你瘋了嗎？劉米娜？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"전에 싸워봤으면 알 텐데? 저 망할 년, 결코 만만한 상대가 아니야……!","JPN":"戦ったことがあるならわかるでしょ。あの女、甘く見ていい相手じゃない……！","ENG":"You fought her before, remember? That damn woman is no pushover...!","TWN":"之前交過手的話就該知道吧？那個該死的女人，絕對不是好對付的對手！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부탁할게, 에이미.","JPN":"頼むよ、エイミー。","ENG":"Please, Amy.","TWN":"拜託了，艾米。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"한 번만이라도 좋아. 나한테 길을 열어줘.","JPN":"たった一度だけでいい。私に道を作ってほしい。","ENG":"Just once. Open the path for me.","TWN":"哪怕一次也好。給我開條路吧。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내 모든 걸 걸고서, 반드시 성공시킬 테니까.","JPN":"私の全てをかけて、必ず成功させるから。","ENG":"I'll stake everything I have. I will make this work.","TWN":"我會傾盡全力，一定會成功的。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아! 진짜……!","JPN":"ああ、もう……！","ENG":"Ugh! Seriously...!","TWN":"啊！真是的……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아이씨! 나도 이젠 몰라……!","JPN":"くそ、どうなっても知らないよ……！","ENG":"Damn it! Fine, whatever...!","TWN":"煩死了！我也不管了……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어디 한 번 네 마음대로 해 보라고, 유미나!","JPN":"あんたの好きなようにやりな、ヤナギ・ミナ！","ENG":"Do whatever the heck you want, Yoo Mina!","TWN":"劉米娜，你就試試看能不能如願以償吧！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};